        var filtroMale = new FilterPontoVirtualAcessos
        {
            Tipo = 1
        };
        var resultMale = _serviceS.WFiltroPontoVirtualAcessos(filtroMale);
        resultMale.Should().NotBeNull();
        var maleParam = resultMale.Value.parametros.FirstOrDefault(p => p.ParameterName == $"@{DBPontoVirtualAcessosDicInfo.Tipo}");
        maleParam.Should().NotBeNull();
        maleParam.Value.Should().Be(1);
    }

    [Fact]
    public void WFiltro_TipoAsFirstFilter_ShouldNotIncludeLogicalOperatorInWhereClause()
    {
        // Arrange
        var filtro = new FilterPontoVirtualAcessos
        {
            Tipo = 1,
            LogicalOperator = " AND "
        };
        // Act
        var result = _serviceS.WFiltroPontoVirtualAcessos(filtro);
        // Assert
        result.Should().NotBeNull();
        result.Value.where.Should().StartWith($"[{DBPontoVirtualAcessosDicInfo.PTabelaNome}].[{DBPontoVirtualAcessosDicInfo.Tipo}] = @{DBPontoVirtualAcessosDicInfo.Tipo}");
        result.Value.where.Should().NotStartWith(" AND ");
    }

